#include <iostream>
#include <string>
#include <vector>
#include <cstdio>
#include <stdexcept>
#include <algorithm>
#include <sstream>

std::string run_program(const std::string& program_path, const std::string& input) {
    std::string command;
#ifdef _WIN32
    command = "echo " + input + " | \"" + program_path + "\"";
#else
    command = "echo \"" + input + "\" | " + program_path;
#endif

    char buffer[128];
    std::string result = "";
    FILE* pipe = popen(command.c_str(), "r");
    if (!pipe) {
        throw std::runtime_error("popen() failed for command: " + command);
    }
    while (!feof(pipe)) {
        if (fgets(buffer, 128, pipe) != nullptr) {
            result += buffer;
        }
    }
    pclose(pipe);
    return result;
}

std::string extract_last_line(const std::string& raw_output) {
    std::istringstream iss(raw_output);
    std::string line;
    std::string last_non_empty_line = "";
    while (std::getline(iss, line)) {
        size_t first = line.find_first_not_of(" \t\r\n");
        if (std::string::npos == first) continue;
        size_t last = line.find_last_not_of(" \t\r\n");
        std::string trimmed_line = line.substr(first, (last - first + 1));
        last_non_empty_line = trimmed_line;
    }
    return last_non_empty_line;
}

int main() {
    std::string program_path = "./solution_program"; 
#ifdef _WIN32
    program_path = ".\\solution_program.exe";
#endif

    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"0", "0h 0m 0s"},
        {"59", "0h 0m 59s"},
        {"60", "0h 1m 0s"},
        {"3599", "0h 59m 59s"},
        {"3600", "1h 0m 0s"},
        {"3601", "1h 0m 1s"},
        {"7200", "2h 0m 0s"},
        {"86399", "23h 59m 59s"},
        {"90000", "25h 0m 0s"},
        {"123456789", "34293h 31m 29s"},
        {"-100", "0h -1m -40s"},
        {"abc", "0h 0m 0s"}
    };

    for (size_t i = 0; i < test_cases.size(); ++i) {
        const auto& tc = test_cases[i];
        std::string input_str = tc.first;
        std::string expected_output = tc.second;

        try {
            std::string actual_output_raw = run_program(program_path, input_str);
            std::string actual_output = extract_last_line(actual_output_raw);

            if (actual_output == expected_output) {
                std::cout << "Test PASSED for input: " << input_str << std::endl;
            } else {
                std::cout << "Test FAILED for input: " << input_str << std::endl;
                std::cout << "  Expected: '" << expected_output << "'" << std::endl;
                std::cout << "  Actual:   '" << actual_output << "'" << std::endl;
            }
        } catch (const std::exception& e) {
            std::cerr << "Error running program for input " << input_str << ": " << e.what() << std::endl;
            std::cout << "Test FAILED for input: " << input_str << " (Exception)" << std::endl;
        }
    }
    return 0;
}
